// app/page.tsx
import { getAllProducts, syncLatestCatalog } from '@/lib/db';

export const metadata = {
  title: 'Catalog Admin',
  description: 'Read-heavy product catalog with background sync'
};

function formatCurrency(value: number) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0
  }).format(value);
}

export default async function Page() {
  const products = await getAllProducts();
  const totalInventory = products.reduce((sum, product) => sum + product.inventory, 0);
  const lastUpdated = products.reduce(
    (latest, product) => (product.updatedAt > latest ? product.updatedAt : latest),
    products[0]?.updatedAt ?? new Date().toISOString()
  );

  return (
    <main className="page-shell">
      <section className="hero">
        <div>
          <p className="eyebrow">Admin catalog</p>
          <h1>Browse the product catalog without blocking on fresh recomputation.</h1>
          <p className="lede">
            Product reads are cached with the <code>products</code> tag. Syncing ERP/PIM changes
            updates the shared catalog in the background so operators can keep working.
          </p>
        </div>

        <form action={syncLatestCatalog}>
          <button type="submit" className="sync-button">
            Sync latest catalog
          </button>
          <p className="form-note">Submits immediately and refreshes tagged catalog data shortly after.</p>
        </form>
      </section>

      <section className="stats">
        <div className="stat-card">
          <span className="stat-label">Products</span>
          <strong>{products.length}</strong>
        </div>
        <div className="stat-card">
          <span className="stat-label">Units in stock</span>
          <strong>{totalInventory}</strong>
        </div>
        <div className="stat-card">
          <span className="stat-label">Last refresh</span>
          <strong>{new Date(lastUpdated).toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' })}</strong>
        </div>
      </section>

      <section className="catalog-panel">
        <div className="catalog-header">
          <h2>Catalog snapshot</h2>
          <p>Stale data is acceptable for a brief period while the background sync settles.</p>
        </div>

        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>SKU</th>
                <th>Product</th>
                <th>Price</th>
                <th>Inventory</th>
                <th>Availability</th>
                <th>Updated</th>
              </tr>
            </thead>
            <tbody>
              {products.map(product => (
                <tr key={product.id}>
                  <td>#{product.id}</td>
                  <td>{product.name}</td>
                  <td>{formatCurrency(product.price)}</td>
                  <td>{product.inventory}</td>
                  <td>
                    <span className={`status status-${product.availability.toLowerCase().replace(/\s+/g, '-')}`}>
                      {product.availability}
                    </span>
                  </td>
                  <td>{new Date(product.updatedAt).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' })}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </main>
  );
}


