import { unstable_cache } from 'next/cache';

type Product = {
  id: number;
  name: string;
  price: number;
  inventory: number;
  availability: string;
  updatedAt: string;
};

const catalogSnapshot: Product[] = [
  {
    id: 1,
    name: 'Laptop',
    price: 999,
    inventory: 42,
    availability: 'In stock',
    updatedAt: '2026-07-11T08:00:00.000Z'
  },
  {
    id: 2,
    name: 'Phone',
    price: 699,
    inventory: 14,
    availability: 'Low stock',
    updatedAt: '2026-07-11T08:00:00.000Z'
  },
  {
    id: 3,
    name: 'Tablet',
    price: 499,
    inventory: 0,
    availability: 'Backordered',
    updatedAt: '2026-07-11T08:00:00.000Z'
  },
  {
    id: 4,
    name: 'Headphones',
    price: 199,
    inventory: 88,
    availability: 'In stock',
    updatedAt: '2026-07-11T08:00:00.000Z'
  },
  {
    id: 5,
    name: 'Watch',
    price: 299,
    inventory: 23,
    availability: 'In stock',
    updatedAt: '2026-07-11T08:00:00.000Z'
  }
];

async function getAllProductsUncached(): Promise<Product[]> {
  await new Promise(resolve => setTimeout(resolve, 100));

  return catalogSnapshot;
}

export const getAllProducts = unstable_cache(getAllProductsUncached, ['products'], {
  revalidate: false,
  tags: ['products']
});

export async function syncLatestCatalog() {
  'use server';

  await new Promise(resolve => setTimeout(resolve, 1200));

  const now = new Date().toISOString();

  for (const product of catalogSnapshot) {
    product.price += 1;
    product.inventory = Math.max(0, product.inventory - 1);
    product.availability =
      product.inventory === 0 ? 'Backordered' : product.inventory < 20 ? 'Low stock' : 'In stock';
    product.updatedAt = now;
  }

  const { revalidateTag } = await import('next/cache');
  revalidateTag('products', 'max');
}
